local G = DYCInfoPanel local require = G.DYCModRequire local odwutil = require( "dyc_odwutil" ) local ShowObjectDetail = odwutil.ShowObjectDetail local ClearUpdateOdwTask = odwutil.ClearUpdateOdwTask local CreateUpdateOdwTask = odwutil.CreateUpdateOdwTask local function GetWorld() return rawget(_G, "GetWorld" ) and rawget(_G, "GetWorld" )() or rawget(_G, "TheWorld" ) end local function OnGainFocus(self, ...) local world = GetWorld() if world then ShowObjectDetail(world, self) ClearUpdateOdwTask(self) CreateUpdateOdwTask(self, world) end return self.dycOldOnGainFocus(self, ...) end local function OnLoseFocus(self, ...) ShowObjectDetail(nil, self) ClearUpdateOdwTask(self) return self.dycOldOnLoseFocus(self, ...) end local function DYCUIClock(self) self.dycOldOnGainFocus = self.OnGainFocus self.OnGainFocus = OnGainFocus self.dycOldOnLoseFocus = self.OnLoseFocus self.OnLoseFocus = OnLoseFocus if self.face then self.face:SetClickable(true) end end return DYCUIClock 